 * ```typescript
 * const manager = new ApprovalManager();
 *
 * // CLI에서 핸들러 등록
 * manager.setHandler(async (request) => {
 *   const answer = await askUser(`Approve ${request.reason}? [Y/n/a]`);
 *   if (answer === 'a') return 'always_approve';
 *   return answer === 'n' ? 'reject' : 'approve';
