     * 버퍼에 아이템이 있으면 즉시 반환하고, 없으면 push될 때까지 대기한다.
     *
     * @returns 큐에서 꺼낸 아이템
     */
    async shift() {
        if (this.closed && this.buffer.length === 0) {
            throw new Error("AsyncCompletionQueue closed");
        }
        const item = this.buffer.shift();
        if (item !== undefined) {
            return item;
        }
