    },
    "test-watcher": {
        name: "Test Watcher",
        intervalMs: 120_000,
        command: "npx jest --watchAll=false --bail 2>&1",
    },
    "security-scanner": {
        name: "Security Scanner",
        intervalMs: 300_000,
        command: "npm audit --json 2>&1 || true",
    },
    "perf-analyzer": {
        name: "Performance Analyzer",
        intervalMs: 600_000,
        command: "echo 'perf-check-placeholder'",
    },
    "dependency-watcher": {
