            { type: "test-watcher", enabled: false },
            { type: "security-scanner", enabled: true },
            { type: "dependency-watcher", enabled: true },
        ];
        for (const { type, enabled } of types) {
            const defaults = DEFAULT_CONFIGS[type];
            this.register({
                id: `default:${type}`,
