                const tokens = r.tokensUsed.toLocaleString();
                const duration = `${(r.durationMs / 1000).toFixed(1)}s`;
                const reason = r.terminationReason.slice(0, 40);
                lines.push(`| ${r.taskName} | ${status} | ${tokens} | ${duration} | ${reason} |`);
            }
            lines.push("");
            // ─── Error Details ───
