// ─── CapabilityGraph ───
class CapabilityGraph extends EventEmitter {
    storageFile;
    storageDir;
    nodes = new Map();
    // Adjacency list keyed by fromId
    edges = new Map();
    _saveTimer = null;
    constructor(storageDir) {
        super();
        this.storageDir =
            storageDir ?? join(homedir(), ".yuan");
        this.storageFile = join(this.storageDir, "capability-graph.json");
