    /**
     * Attempt `git stash` and return the stash ref (e.g. "stash@{0}").
     * Returns undefined if git is unavailable, not a repo, or the tree is clean.
     */
    tryGitStash() {
        try {
            const output = execSync("git stash", {
                cwd: this.projectPath,
                stdio: "pipe",
                encoding: "utf-8",
