    for (const entry of entries) {
        if (entry.isDirectory()) {
            if (excludeDirs.has(entry.name) || entry.name.startsWith(".")) {
                // Skip hidden dirs (except project root itself) and excluded dirs
                if (!excludeDirs.has(entry.name))
                    continue;
                continue;
