        // BFS reverse (files that import this file)
        const reverseQueue = [];
        const directDeps = this.reverseDepMap.get(absFile);
        if (directDeps) {
            for (const dep of directDeps) {
                if (!seen.has(dep)) {
                    seen.add(dep);
                    results.push({ path: dep, relation: "imported_by", depth: 1 });
                    reverseQueue.push({ path: dep, depth: 1 });
                }
            }
        }
        while (reverseQueue.length > 0) {
            const current = reverseQueue.shift();
            if (current.depth >= maxDepth)
                continue;
            const deps = this.reverseDepMap.get(current.path);
            if (!deps)
                continue;
            for (const dep of deps) {
                if (!seen.has(dep)) {
                    seen.add(dep);
                    results.push({ path: dep, relation: "imported_by", depth: current.depth + 1 });
                    reverseQueue.push({ path: dep, depth: current.depth + 1 });
                }
            }
        }
        return results;
    }
    /**
     * Find where a function is called across the project.
     * Searches all indexed file contents for occurrences of the function name
     * that look like call sites.
     *
     * @param functionName - Name of the function to search for
     * @param filePath - File where the function is defined (excluded from results)
     * @returns Array of call chain entries with file, line, and context
     */
    async getCallChain(functionName, filePath) {
        const absFile = resolve(filePath);
        const results = [];
        const callPattern = new RegExp(`\\b${functionName}\\s*(?:<[^>]*>)?\\s*\\(`, "g");
        for (const [file, content] of this.fileContents) {
            if (file === absFile)
                continue;
            const lines = content.split("\n");
            for (let i = 0; i < lines.length; i++) {
                if (callPattern.test(lines[i])) {
                    results.push({
                        file,
                        line: i + 1,
                        context: lines[i].trim(),
                    });
                }
                callPattern.lastIndex = 0;
            }
        }
        return results;
    }
    /**
     * Calculate the impact radius of a file — how many files depend on it
     * directly and transitively, with a risk score.
     *
     * @param filePath - Absolute or project-relative path of the file
     * @returns Direct/transitive dependent counts and a risk score
     */
    async getImpactRadius(filePath) {
        const absFile = resolve(filePath);
        // Direct dependents
        const directDeps = this.reverseDepMap.get(absFile);
        const directCount = directDeps ? directDeps.size : 0;
        // Transitive dependents (BFS)
        const visited = new Set([absFile]);
        const queue = directDeps ? [...directDeps] : [];
        for (const d of queue)
            visited.add(d);
        let transitiveCount = 0;
        while (queue.length > 0) {
            const current = queue.shift();
            transitiveCount++;
            const deps = this.reverseDepMap.get(current);
            if (!deps)
                continue;
            for (const dep of deps) {
                if (!visited.has(dep)) {
                    visited.add(dep);
                    queue.push(dep);
                }
            }
        }
        // Transitive count includes direct dependents; subtract to get only indirect
        const indirectCount = transitiveCount - directCount;
        return {
            directDependents: directCount,
            transitiveDependents: indirectCount,
            riskScore: directCount * 2 + indirectCount,
        };
    }
    // ─── Search ───
    /**
     * Search symbols by a query string using token-based fuzzy matching.
     * Splits the query into tokens and scores symbols by match count against
     * name, kind, file path, and JSDoc.
     *
     * @param query - Search query (space-separated tokens)
     * @param limit - Maximum results to return (default 10)
     * @returns Ranked search results with relevance scores
     */
    searchSymbols(query, limit = 10) {
        const tokens = query
            .toLowerCase()
            .split(/[\s_\-./]+/)
            .filter((t) => t.length > 0);
        if (tokens.length === 0)
            return [];
        const scored = [];
        for (const [name, symbols] of this.index.symbolTable) {
            for (const sym of symbols) {
                const score = this.scoreSymbol(sym, name, tokens);
                if (score > 0) {
                    scored.push({
                        symbol: sym,
                        file: sym.file,
                        relevance: score,
                        snippet: this.getSnippet(sym),
                    });
                }
            }
        }
        // Sort by relevance descending, then by name
        scored.sort((a, b) => b.relevance - a.relevance || a.symbol.name.localeCompare(b.symbol.name));
        return scored.slice(0, limit);
    }
    /**
     * Search for symbols whose return type or type annotation matches a pattern.
     *
     * @param typePattern - Regex pattern to match against types
     * @returns Matching symbols
     */
    searchByType(typePattern) {
        const re = new RegExp(typePattern, "i");
        const results = [];
        for (const symbols of this.index.symbolTable.values()) {
            for (const sym of symbols) {
                if (sym.returnType && re.test(sym.returnType)) {
                    results.push(sym);
                }
                if (sym.params) {
                    for (const param of sym.params) {
                        if (re.test(param.type)) {
                            results.push(sym);
                            break;
                        }
                    }
                }
            }
        }
        return results;
    }
    // ─── File analysis ───
    /**
     * Get the analysis for a specific file.
     *
     * @param file - Absolute file path
     * @returns FileAnalysis or undefined if not indexed
     */
    getFileAnalysis(file) {
        return this.index.files.get(resolve(file));
    }
    /**
     * Get files exceeding a cyclomatic complexity threshold.
     *
     * @param threshold - Minimum cyclomatic complexity (default 20)
     * @returns Files exceeding the threshold, sorted by complexity descending
     */
    getComplexFiles(threshold = 20) {
        const results = [];
        for (const analysis of this.index.files.values()) {
            if (analysis.complexity.cyclomatic >= threshold) {
                results.push(analysis);
            }
        }
        results.sort((a, b) => b.complexity.cyclomatic - a.complexity.cyclomatic);
        return results;
    }
    /**
     * Identify hotspots — files with high complexity AND many dependents.
     *
     * @returns Hotspot entries sorted by combined score descending
     */
    getHotspots() {
        const hotspots = [];
        for (const [file, analysis] of this.index.files) {
            const deps = this.reverseDepMap.get(file);
            const depCount = deps ? deps.size : 0;
            hotspots.push({
                file,
                complexity: analysis.complexity.cyclomatic,
                dependencies: depCount,
            });
        }
        // Sort by combined score (complexity * log(deps+1))
        hotspots.sort((a, b) => {
            const scoreA = a.complexity * Math.log2(a.dependencies + 1);
            const scoreB = b.complexity * Math.log2(b.dependencies + 1);
            return scoreB - scoreA;
        });
        return hotspots;
    }
    // ─── Stats ───
    /**
     * Get summary statistics for the indexed codebase.
     *
     * @returns Aggregate stats
     */
    getStats() {
        let totalCyclomatic = 0;
        let totalCognitive = 0;
        let totalLoc = 0;
        let maxComplexity = 0;
        for (const analysis of this.index.files.values()) {
            totalCyclomatic += analysis.complexity.cyclomatic;
            totalCognitive += analysis.complexity.cognitive;
            totalLoc += analysis.complexity.loc;
            if (analysis.complexity.cyclomatic > maxComplexity) {
                maxComplexity = analysis.complexity.cyclomatic;
            }
        }
        const n = this.index.totalFiles || 1;
        return {
            totalFiles: this.index.totalFiles,
            totalSymbols: this.index.totalSymbols,
            avgComplexity: Math.round((totalCyclomatic / n) * 100) / 100,
            avgCognitive: Math.round((totalCognitive / n) * 100) / 100,
            maxComplexity,
            avgLoc: Math.round(totalLoc / n),
        };
    }
    // ─── Private: File collection ───
    /**
     * Recursively collect all source files under a directory,
     * skipping excluded directories.
     */
    async collectSourceFiles(dir) {
        const results = [];
        let entries;
        try {
            entries = await readdir(dir, { withFileTypes: true });
        }
        catch {
            return results;
        }
        for (const entry of entries) {
            const fullPath = join(dir, entry.name);
            if (entry.isDirectory()) {
                if (!SKIP_DIRS.has(entry.name) && !entry.name.startsWith(".")) {
                    const sub = await this.collectSourceFiles(fullPath);
                    results.push(...sub);
                }
            }
            else if (entry.isFile() && this.isSupportedSourceFile(entry.name)) {
                results.push(fullPath);
            }
        }
        return results;
    }
    // ─── Private: File support check ───
    /**
     * Check if a file is a supported source file.
     * Uses LanguageSupport for multi-language detection when available,
     * otherwise falls back to built-in TS/JS extensions.
     */
    isSupportedSourceFile(fileName) {
        const ext = extname(fileName);
        if (SOURCE_EXTENSIONS.has(ext))
            return true;
        if (this.languageSupport) {
            const lang = this.languageSupport.detectLanguage(fileName);
            return lang !== "unknown";
        }
        return false;
    }
    // ─── Private: File analysis ───
    /**
     * Analyze a single source file — extract symbols, imports, exports,
     * and compute complexity metrics.
     *
     * For TypeScript/JavaScript files, first attempts AST-based extraction via AstAnalyzer
     * (ts-morph) for improved accuracy, then merges/falls back to regex-based extraction.
     * When LanguageSupport is available and the file is not TS/JS, uses language-specific
     * patterns for symbol extraction.
     */
    async analyzeFile(filePath, content) {
        const ext = extname(filePath);
        const isTsJs = ext === ".ts" || ext === ".tsx" || ext === ".js" || ext === ".jsx";
        // Detect language — use LanguageSupport when available, fallback to TS/JS
        let language;
        if (isTsJs) {
            language = ext === ".ts" || ext === ".tsx" ? "typescript" : "javascript";
        }
        else if (this.languageSupport) {
            language = this.languageSupport.detectLanguage(filePath, content);
        }
        else {
            language = "javascript"; // shouldn't happen, but safe fallback
        }
        const lines = content.split("\n");
        let symbols;
        if (isTsJs || !this.languageSupport) {
            // For TS/JS: try AST-based extraction first for accuracy, fall back to regex
            symbols = await this.extractSymbolsWithAstFallback(filePath, content, lines);
        }
        else {
            // For other languages: use LanguageSupport patterns
            symbols = this.extractSymbolsWithLanguageSupport(filePath, content, lines, language);
        }
        const imports = this.extractImports(content);
        const exports = this.extractExports(content);
        const callEdges = this.extractCallEdges(filePath, content, lines, symbols);
        const complexity = this.computeComplexity(content, lines, imports.length);
        return { file: filePath, language, symbols, imports, exports, callEdges, complexity };
    }
    /**
     * Try AST-based symbol extraction (ts-morph) for a TS/JS file.
     * If AstAnalyzer returns results, merges them with regex results to fill in detail
     * (params, jsdoc, etc.) not available from the AST layer alone.
     * Falls back to pure regex extraction on any error or empty AST result.
     */
    async extractSymbolsWithAstFallback(filePath, content, lines) {
        try {
            const astSymbols = await this.astAnalyzer.extractSymbols(filePath);
            if (astSymbols.length > 0) {
                // AstAnalyzer succeeded — use regex extraction to get full detail (params, jsdoc…),
                // but trust AST line numbers and exported status for the symbols it found.
                const regexSymbols = this.extractSymbols(filePath, content, lines);
                return this.mergeAstAndRegexSymbols(astSymbols, regexSymbols, filePath);
            }
        }
        catch {
            // AstAnalyzer failed — fall through to regex
        }
        return this.extractSymbols(filePath, content, lines);
    }
    /**
     * Merge AST symbol info (accurate line numbers, exported status) with regex symbol info
     * (params, jsdoc, return types). AST results are authoritative for line/endLine/exported/isDefault.
     * Symbols found by AST but not regex are included as minimal entries (no params/jsdoc).
     * Symbols found by regex but not AST are included as-is (regex may have false positives
     * for unexported symbols inside bodies, which is acceptable).
     */
    mergeAstAndRegexSymbols(astSymbols, regexSymbols, filePath) {
        const merged = [];
        const regexByName = new Map();
        for (const sym of regexSymbols) {
            const arr = regexByName.get(sym.name) ?? [];
            arr.push(sym);
            regexByName.set(sym.name, arr);
        }
        const astNames = new Set();
        for (const astSym of astSymbols) {
            const displayName = astSym.isDefault && astSym.name === "__default__" ? "default" : astSym.name;
            astNames.add(displayName);
            // Find the best matching regex symbol (by name, pick closest line)
            const candidates = regexByName.get(displayName) ?? [];
            let best;
            let bestLineDiff = Infinity;
            for (const candidate of candidates) {
                const diff = Math.abs(candidate.line - astSym.line);
                if (diff < bestLineDiff) {
                    bestLineDiff = diff;
                    best = candidate;
                }
            }
            if (best && bestLineDiff <= 5) {
                // Merge: use AST accuracy for line/endLine/exported/isDefault, regex for the rest
                merged.push({
                    ...best,
                    line: astSym.line,
                    endLine: astSym.endLine,
                    exported: true, // AST found it as exported declaration
                    isDefault: astSym.isDefault,
                });
            }
            else {
                // AST found a symbol regex missed — include as a minimal entry
                merged.push({
                    name: displayName,
                    kind: astSym.kind,
                    file: filePath,
                    line: astSym.line,
                    endLine: astSym.endLine,
                    exported: true,
                    isDefault: astSym.isDefault,
                    isAsync: false,
                });
            }
        }
        // Include regex-found symbols not covered by AST (unexported/internal — AST only returns exports)
        for (const sym of regexSymbols) {
            if (!astNames.has(sym.name)) {
                merged.push(sym);
            }
        }
        return merged;
    }
    /**
