     * @param query - 검색 쿼리
     * @returns 관련성 점수 (0-1)
     */
    scoreRelevance(item, query) {
        let score = 0;
        // 1. 파일 매치 (0.3)
        if (item.file && query.currentFiles.length > 0) {
            const fileMatch = query.currentFiles.some((f) => item.file === f || item.content.includes(f));
            if (fileMatch)
                score += 0.3;
        }
        else if (query.currentFiles.length > 0) {
