        const now = Date.now();
        const age = now - item.timestamp;
        const maxAge = 30 * 60 * 1000; // 30분
        const recency = Math.max(0, 1 - age / maxAge);
        score += 0.2 * recency;
        // 4. 우선순위 점수 (0.15)
        const priorityScore = PRIORITY_SCORES[item.priority] / 5; // 0-1 정규화
