        const nonSystemMessages = messages.filter((m) => m.role !== "system");
        const recentMessages = this.takeRecentConversationWindow(nonSystemMessages, 6);
        const olderMessages = nonSystemMessages.slice(0, Math.max(0, nonSystemMessages.length - recentMessages.length));
        const result = [...systemMessages];
        if (olderMessages.length > 0) {
            result.push({
                role: "system",
                content: "[Compressed conversation state]\n" +
                    this.summarizeMessages(olderMessages).slice(0, 1200),
            });
        }
        for (const msg of recentMessages) {
            if (msg.role === "tool" && msg.content) {
                result.push({
                    ...msg,
                    content: this.truncateToolResult(contentToString(msg.content)),
                });
            }
            else {
                result.push(msg);
            }
        }
        let currentTokens = this.estimateTokens(result);
        if (currentTokens <= targetTokens) {
            return result;
        }
        // 여전히 크면, 오래된 non-system부터 제거
        while (result.length > systemMessages.length + 2 && currentTokens > targetTokens) {
            const removeIndex = systemMessages.length;
            if (removeIndex >= result.length)
                break;
            const candidate = result[removeIndex];
            if (candidate.role === "tool")
                break;
            if (candidate.role === "assistant" && candidate.tool_calls?.length)
                break;
            result.splice(removeIndex, 1);
            currentTokens = this.estimateTokens(result);
        }
        if (currentTokens <= targetTokens) {
            return result;
        }
        // 그래도 크면 최근 메시지 본문 자체를 잘라서 맞춘다.
        for (let i = result.length - 1; i >= systemMessages.length && currentTokens > targetTokens; i--) {
            const msg = result[i];
            result[i] = this.truncateMessageForBudget(msg, 400);
            currentTokens = this.estimateTokens(result);
        }
        // 마지막 fallback: system + 마지막 user/assistant/tool 흐름만 남긴다.
        if (currentTokens > targetTokens) {
            const minimalRecent = this.takeRecentConversationWindow(nonSystemMessages, 3).map((msg) => this.truncateMessageForBudget(msg, 250));
            // Repair orphaned tool_calls: if an assistant message has tool_calls
            // but the matching tool result messages are not in minimalRecent, include them.
            const repairedMinimal = [];
            for (let i = 0; i < minimalRecent.length; i++) {
                repairedMinimal.push(minimalRecent[i]);
                const msg = minimalRecent[i];
                if (msg.role === "assistant" && msg.tool_calls?.length) {
                    const expectedIds = new Set(msg.tool_calls.map((tc) => tc.id));
                    // Remove IDs already covered by subsequent tool messages in minimalRecent
                    for (let j = i + 1; j < minimalRecent.length; j++) {
                        if (minimalRecent[j].role === "tool") {
                            expectedIds.delete(minimalRecent[j].tool_call_id ?? "");
                        }
                    }
                    // Find missing tool results from the full nonSystemMessages
                    if (expectedIds.size > 0) {
                        for (const origMsg of nonSystemMessages) {
                            if (origMsg.role === "tool" && expectedIds.has(origMsg.tool_call_id ?? "")) {
                                repairedMinimal.push(this.truncateMessageForBudget(origMsg, 250));
                                expectedIds.delete(origMsg.tool_call_id ?? "");
                            }
                        }
                    }
                }
            }
            return [...systemMessages, ...repairedMinimal];
        }
        return result;
    }
    /**
     * 최근 대화 윈도우를 가져오되, assistant(tool_calls) ↔ tool pair가
     * 깨지지 않도록 뒤에서부터 묶어서 보존한다.
     */
    takeRecentConversationWindow(messages, count) {
        const start = Math.max(0, messages.length - count);
        const recent = messages.slice(start);
        if (recent.length === 0)
            return recent;
        const repaired = [];
        for (let i = 0; i < recent.length; i++) {
            repaired.push(recent[i]);
            const msg = recent[i];
            if (msg.role === "assistant" && msg.tool_calls?.length) {
                const expectedIds = new Set(msg.tool_calls.map((tc) => tc.id));
                let j = i + 1;
                while (j < recent.length && recent[j].role === "tool") {
                    if (expectedIds.has(recent[j].tool_call_id ?? "")) {
                        repaired.push(recent[j]);
                    }
                    j++;
                }
            }
        }
        return repaired;
    }
    /**
     * 런타임 시스템 메시지를 rolling window으로 제한.
     * 첫 번째 시스템 메시지(기본 프롬프트)는 항상 유지하고,
     * 나머지 런타임 시스템 메시지는 최근 maxRuntime개만 유지.
     */
    pruneSystemMessages(systemMessages, maxRuntime = 15) {
        if (systemMessages.length <= maxRuntime + 1) {
            return systemMessages;
        }
        // 첫 번째(기본 프롬프트) + 최근 maxRuntime개 런타임 메시지
        const base = systemMessages[0];
        const runtime = systemMessages.slice(1);
        const kept = runtime.slice(-maxRuntime);
        return [base, ...kept];
    }
    summarizeMessages(messages) {
        const actions = [];
        let userMsgCount = 0;
        let toolCallCount = 0;
        for (const msg of messages) {
            if (msg.role === "user") {
                userMsgCount++;
                if (msg.content) {
                    const text = contentToString(msg.content);
                    const preview = text.slice(0, 100);
                    actions.push(`User: ${preview}${text.length > 100 ? "..." : ""}`);
                }
            }
            else if (msg.role === "assistant" && msg.tool_calls) {
                toolCallCount += msg.tool_calls.length;
                for (const tc of msg.tool_calls) {
                    actions.push(`Tool: ${tc.name}`);
                }
            }
        }
        return [
            `${userMsgCount} user messages, ${toolCallCount} tool calls.`,
            ...actions.slice(0, 10),
            actions.length > 10
                ? `... and ${actions.length - 10} more actions`
                : "",
        ]
            .filter(Boolean)
            .join("\n");
    }
    truncateToolResult(content) {
        const MAX = 500;
        if (content.length <= MAX)
            return content;
        return content.slice(0, 200) + "\n...(truncated)...\n" + content.slice(-200);
    }
    /**
     * 메시지 하나를 예산 친화적으로 축약한다.
     * tool_call / tool_call_id 구조는 유지하고 content만 줄인다.
     */
    truncateMessageForBudget(message, maxChars) {
        if (!message.content)
            return message;
        if (typeof message.content === "string") {
            if (message.content.length <= maxChars)
                return message;
            return {
                ...message,
                content: message.content.slice(0, Math.floor(maxChars / 2)) +
                    "\n...[compressed]...\n" +
                    message.content.slice(-Math.floor(maxChars / 2)),
            };
        }
        const content = contentToString(message.content);
        if (content.length <= maxChars)
            return message;
        return {
            ...message,
            content: content.slice(0, Math.floor(maxChars / 2)) +
                "\n...[compressed]...\n" +
                content.slice(-Math.floor(maxChars / 2)),
        };
    }
    /**
     * 문자열의 대략적인 토큰 수를 추정 (근사치).
     *
     * **추정 방식:**
     * - 영어/ASCII 텍스트: ~4 characters per token
     * - CJK/한국어 텍스트 (U+3000–U+9FFF, U+AC00–U+D7AF): ~2 characters per token
     * - 혼합 텍스트는 각 범위의 문자 수를 분리하여 합산
     *
     * **오차 범위:**
     * - 영어: 실제 토큰 대비 ~±20% 오차 (서브워드 분할 특성상 변동)
     * - CJK/한국어: ~±20% 이상 오차 가능 (모델별 토크나이저 차이가 큼)
     * - 코드, 특수문자, 긴 단어 등에서 오차가 더 커질 수 있음
     *
     * **의도적 설계:**
     * BYOK 환경에서는 사용자가 다양한 모델(Claude, GPT, Gemini 등)을
     * 자유롭게 선택하므로 모델별 토크나이저에 접근할 수 없다.
     * 따라서 정확한 토큰 카운팅 대신 범용 근사치를 사용하며,
     * 컨텍스트 오버플로우는 outputReserve 마진으로 방어한다.
     */
    estimateStringTokens(str) {
        // 캐시 히트 확인
        const cached = this._tokenCache.get(str);
        if (cached !== undefined)
            return cached;
        // CJK 문자 비율 체크 — static regex 재사용 (match()는 lastIndex 무관)
        const cjkCount = (str.match(ContextManager.CJK_REGEX) ?? []).length;
        const nonCjkCount = str.length - cjkCount;
        const result = Math.ceil(nonCjkCount / 4 + cjkCount / 2);
        // LRU-evict: 최대 500개 유지
        if (this._tokenCache.size >= 500) {
            const firstKey = this._tokenCache.keys().next().value;
            if (firstKey !== undefined)
                this._tokenCache.delete(firstKey);
        }
        this._tokenCache.set(str, result);
        return result;
    }
}


