        for (const [from, to] of plan.dependencies) {
            inDegree.set(to, (inDegree.get(to) ?? 0) + 1);
        }
        const queue = [];
        for (const [id, deg] of inDegree) {
            if (deg === 0)
                queue.push(id);
        }
        let visited = 0;
        while (queue.length > 0) {
            const id = queue.shift();
            visited++;
            for (const [from, to] of plan.dependencies) {
                if (from !== id)
                    continue;
