// ─── Regex patterns ───
// import { X, Y } from "Z"  |  import X from "Z"  |  import * as X from "Z"
const IMPORT_RE = /import\s+(?:type\s+)?(?:\{([^}]*)\}|(\w+)|\*\s+as\s+(\w+))\s+from\s+["']([^"']+)["']/g;
