            systemPrompt: obj.systemPrompt,
            allowedTools,
            reason: obj.reason,
        };
    }
    /** 기존 롤과 중복 확인 */
    validateNoDuplicate(name, existingRoles) {
        // 이미 활성화된 동적 롤과 중복 확인
        if (this.dynamicRoles.some((r) => r.name === name)) {
            throw new Error(`Dynamic role "${name}" already exists in this session`);
        }
        // 기존 롤(고정 포함)과 중복 확인
        for (const role of existingRoles) {
            const roleName = typeof role === "string" ? role : role.name;
            if (roleName === name) {
                throw new Error(`Dynamic role "${name}" conflicts with existing role`);
            }
        }
    }
    /** 패턴 학습 — 빈도 기록 */
    recordPattern(role) {
        const existing = this.patterns.get(role.name);
        if (existing) {
            existing.frequency += 1;
            existing.lastUsedAt = Date.now();
        }
        else {
            this.patterns.set(role.name, {
                name: role.name,
                description: role.description,
                frequency: 1,
                lastUsedAt: Date.now(),
            });
        }
    }
}


