            return {
                strategy: "retry",
                reason: `First attempt with ${category} — retry with targeted fix.`,
                context: { category, attemptNumber },
            };
        }
        // Too many strategies tried → escalate
        if (previousStrategies.length >= this.config.escalateThreshold) {
