        return "TypeScript";
    if (/ENOENT|no such file/i.test(raw))
        return "FileNotFound";
    if (/EACCES|permission denied/i.test(raw))
        return "Permission";
    if (/test/i.test(raw) && /fail/i.test(raw))
        return "Test";
    if (/build/i.test(raw) && /fail/i.test(raw))
        return "Build";
    if (raw.trim().length > 0)
