            tags.push("nextjs");
        if (names.some(n => n === "vite"))
            tags.push("vite");
        if (names.some(n => n === "react"))
            tags.push("react");
        if (names.some(n => n === "vue"))
            tags.push("vue");
        if (names.some(n => n.startsWith("@nestjs")))
