        appendFileSync(join(dir, "failure-surface.jsonl"), JSON.stringify(entry) + "\n");
    }
    catch { /* non-fatal */ }
}
function classifyFailure(terminationReason, lastToolError) {
    if (terminationReason === "BUDGET_EXHAUSTED")
        return "budget_exhausted";
    if (terminationReason === "MAX_ITERATIONS")
        return "timeout";
    if (terminationReason === "USER_CANCELLED")
        return "user_cancelled";
    if (!lastToolError)
        return "unknown";
    if (/tsc|TS\d{4}|build/i.test(lastToolError))
        return "build_fail";
    if (/test|FAIL|assertion/i.test(lastToolError))
        return "test_fail";
    return "tool_error";
}


