                const nameStatusMap = new Map();
                const nameStatusOutput = await this.git(["diff", "--name-status", `${base}..HEAD`]);
                for (const l of nameStatusOutput.split("\n")) {
                    const [s, f] = l.split("\t");
                    if (s && f)
                        nameStatusMap.set(f, s);
