        return output
            .trim()
            .split("\n")
            .filter(Boolean)
            .map((line) => {
            const parts = line.split("|");
            return {
                hash: parts[0] ?? "",
                subject: parts[1] ?? "",
                author: parts[2] ?? "",
                date: parts[3] ?? "",
