        let currentDate = "";
        let currentLine = 0;
        for (const line of lines) {
            // Header line: "hash origLine finalLine numLines"
            const headerMatch = /^[0-9a-f]{40}\s+\d+\s+(\d+)/.exec(line);
            if (headerMatch) {
                currentLine = parseInt(headerMatch[1], 10);
