        const plan = {
            id: randomUUID(),
            goal,
            createdAt: Date.now(),
            strategic,
            tactical,
            operational,
            totalEstimatedIterations,
            parallelizableGroups,
            criticalPath,
            estimatedTokenBudget: 0,
        };
        plan.estimatedTokenBudget = this.estimateTokenBudget(plan);
        return plan;
