    // ─── Milestone API (L0) ───
    /**
     * Create a new milestone for multi-session goal tracking.
     *
     * @param title - Human-readable title
     * @param description - Detailed description
     * @param subGoals - L1 strategic goal IDs this milestone encompasses
     * @returns The created Milestone
     */
    createMilestone(title, description, subGoals) {
        const now = new Date().toISOString();
        const milestone = {
            id: `milestone-${randomUUID().slice(0, 8)}`,
            title,
            description,
            status: "pending",
            targetSessions: 1,
            completedSessions: 0,
            subGoals,
            createdAt: now,
            updatedAt: now,
        };
        this.milestones.set(milestone.id, milestone);
        return milestone;
    }
    /**
     * Update the status of an existing milestone.
     *
     * @param id - Milestone ID
     * @param status - New status
