    getActiveMilestone() {
        for (const milestone of this.milestones.values()) {
            if (milestone.status === "in_progress")
                return milestone;
        }
        return null;
    }
    /**
     * Auto-create a milestone from a hierarchical plan.
     * Uses the plan's goal as the title and strategic sub-goals as sub-goal IDs.
     *
     * @param plan - The hierarchical plan to derive a milestone from
     * @returns The created Milestone
     */
    milestoneFromPlan(plan) {
        const subGoalIds = plan.strategic.subGoals.map((sg) => sg.id);
        const estimatedSessions = Math.max(1, Math.ceil(plan.totalEstimatedIterations / 20));
        const milestone = this.createMilestone(plan.goal, plan.strategic.description, subGoalIds);
        milestone.targetSessions = estimatedSessions;
        milestone.updatedAt = new Date().toISOString();
