        if (!trimmed)
            return;
        let message;
        try {
            message = JSON.parse(trimmed);
        }
        catch {
            // Not valid JSON — skip (could be debug output)
            return;
        }
        if (message.jsonrpc !== "2.0")
            return;
        this.handleMessage(message);
    }
    /**
     * Route a parsed JSON-RPC message to the appropriate handler.
     */
    handleMessage(message) {
