if (typeof decayConfidence !== 'undefined') module.exports.decayConfidence = decayConfidence;
if (typeof applyDecayToEntries !== 'undefined') module.exports.applyDecayToEntries = applyDecayToEntries;
if (typeof detectConflict !== 'undefined') module.exports.detectConflict = detectConflict;

