        maxFilesPerRun: base.maxFilesPerRun * mult,
        maxDiffLinesPerRun: base.maxDiffLinesPerRun * mult,
        maxProtectedFilesPerRun: base.maxProtectedFilesPerRun * mult,
        maxCrossPackageTouches: base.maxCrossPackageTouches * mult,
