            return { allowed: false, reason: `Diff lines ${usage.diffLines} exceeds limit ${this.limit.maxDiffLinesPerRun}`, currentUsage: usage, limits: this.limit };
        }
        if (usage.protectedFiles > this.limit.maxProtectedFilesPerRun) {
