                enableSemantic: false,
                enableQuality: false,
                enableReview: false,
                enableDecision: true,
            };
        case "standard":
            return {
                enableStructural: true,
                enableSemantic: true,
                enableQuality: true,
                enableReview: false,
                enableDecision: true,
            };
        case "thorough":
            return {
                enableStructural: true,
                enableSemantic: true,
                enableQuality: true,
                enableReview: true,
                enableDecision: true,
            };
    }
