/**
 * @module reasoning-tree
 * @description Agent reasoning을 트리 구조로 저장
 */
class ReasoningTree {
    nodes = new Map();
    root;
    constructor() {
        this.root = this.createNode("root", "Agent Run");
    }
    createNode(label, text, parentId) {
        const id = `r_${Math.random().toString(36).slice(2, 10)}`;
        const node = {
            id,
            parentId,
            label,
            text,
            createdAt: Date.now(),
            children: [],
        };
        this.nodes.set(id, node);
        if (parentId) {
            const parent = this.nodes.get(parentId);
            if (parent)
                parent.children.push(node);
        }
        return node;
    }
    add(label, text, parentId) {
        const parent = parentId ?? this.root.id;
        return this.createNode(label, text, parent);
    }
    getRoot() {
        return this.root;
    }
    toJSON() {
        return this.root;
    }
    reset() {
        this.nodes.clear();
        this.root = this.createNode("root", "Agent Run");
    }
}


