        process.env["GOOGLE_CLOUD_PROJECT"] ||
        process.env["AZURE_SUBSCRIPTION_ID"] ||
        process.env["OCI_RESOURCE_PRINCIPAL_VERSION"] ||
        process.env["K_SERVICE"]);
}
/** Check if a directory is writable. */
function isWritable(dirPath) {
