            userBase = join(appData, "yuan", username);
        }
        else {
            userBase = join(homedir(), ".yuan", username);
        }
        resolvedPlatform = "windows";
    }
    else if (osPlatform === "darwin") {
        // macOS: ~/Library/Application Support/yuan/<username>/ if writable, else ~/.yuan/<username>/
