    { pattern: /-----BEGIN (?:RSA |EC |DSA )?PRIVATE KEY-----/i, reason: "Private key detected" },
    { pattern: /ghp_[a-zA-Z0-9]{36}/i, reason: "GitHub personal access token" },
    { pattern: /sk-[a-zA-Z0-9]{48,}/i, reason: "OpenAI/Anthropic API key" },
