 * @example
 * ```typescript
 * const scanner = new SecurityScanner({
 *   projectPath: '/path/to/project',
 *   scanSecrets: true,
 *   scanCode: true,
 * });
 * const result = await scanner.scan();
 * console.log(result.summary);
