        if (/\.env(?:\.|$)/.test(filePath)) {
            findings.push({
                id: randomUUID(),
                severity: "medium",
                category: "secret",
                rule: "env-file-committed",
                file: filePath,
                line: 1,
                message: ".env file detected — should not be committed to version control",
                evidence: filePath,
                suggestion: "Add .env files to .gitignore. Use .env.example for templates.",
                confidence: 1.0,
