                    id: randomUUID(),
                    severity: dep.severity,
                    category: "dependency",
                    rule: `deprecated-${dep.name}`,
                    file: "package.json",
                    line: this.findDepLine(packageJsonContent, dep.name),
                    message: dep.message,
                    evidence: `${dep.name}@${allDeps[dep.name]}`,
                    suggestion: dep.suggestion,
                    confidence: 0.8,
