    isIgnored(filePath) {
        const relPath = filePath.startsWith("/")
            ? relative(this.config.projectPath, filePath)
            : filePath;
        const allIgnore = [...DEFAULT_IGNORE_PATHS, ...this.config.ignorePaths];
        for (const pattern of allIgnore) {
            if (relPath.includes(pattern))
                return true;
        }
        return false;
