                findings.push({
                    id: randomUUID(),
                    severity: "medium",
                    category: "config",
                    rule: "csp-unsafe-inline",
                    file: filePath,
                    line: i + 1,
                    message: "CSP allows 'unsafe-inline' for scripts — weakens XSS protection",
                    evidence: "script-src 'unsafe-inline'",
                    suggestion: "Use nonces or hashes instead of 'unsafe-inline' in script-src.",
                    confidence: 0.8,
