            }
            if (/['"]unsafe-eval['"]/.test(line) && /script-src/.test(line)) {
                findings.push({
                    id: randomUUID(),
                    severity: "high",
                    category: "config",
                    rule: "csp-unsafe-eval",
                    file: filePath,
                    line: i + 1,
                    message: "CSP allows 'unsafe-eval' for scripts — enables eval() attacks",
                    evidence: "script-src 'unsafe-eval'",
