 * @example
 * ```typescript
 * const debugLoop = new SelfDebugLoop({ maxAttempts: 5 });
 *
 * // Analyze an error
 * const analysis = debugLoop.analyzeError(errorOutput);
 * console.log(analysis.category, analysis.suggestion);
