     * @returns 삭제된 세션 수
     */
    async cleanup(maxAgeDays = DEFAULT_MAX_AGE_DAYS) {
        let deleted = 0;
        const cutoff = Date.now() - maxAgeDays * 24 * 60 * 60 * 1000;
