            const entries = await fs.promises.readdir(this.baseDir, {
                withFileTypes: true,
            });
            for (const entry of entries) {
                if (!entry.isDirectory())
                    continue;
                const stateFile = path.join(this.baseDir, entry.name, "state.json");
                const snapshot = await this.readJson(stateFile);
                if (!snapshot) {
