        const hasIndependentTasks = this.config.enableParallel &&
            plan.steps.length > 1 &&
            plan.steps.filter((s) => s.dependsOn.length === 0).length >= 2;
        if (hasIndependentTasks) {
            return {
                nextPhase: "parallel",
                updates: {
                    plan,
                    currentStepIndex: 0,
