        this.emit("phase:enter", to, this.state);
    }
    /**
     * 초기 상태를 생성한다.
     */
    createInitialState(goal) {
        return {
            phase: "idle",
            goal,
            plan: null,
            currentStepIndex: 0,
            approaches: [],
            selectedApproach: -1,
            stepResults: [],
            errors: [],
            reflections: [],
            fixAttempts: 0,
            maxFixAttempts: this.config.maxFixAttempts,
            workingMemory: new Map(),
            tokenUsage: { input: 0, output: 0 },
            toolCalls: 0,
            iterationCount: 0,
            startTime: Date.now(),
            userFeedback: [],
        };
    }
    /**
     * 터미널 phase인지 확인한다.
     */
    isTerminal(phase) {
        return TERMINAL_PHASES.has(phase);
    }
