    }
    // Project context
    if (options.projectStructure) {
        sections.push(buildProjectSection(options.projectStructure));
    }
    // YUAN.md
    if (options.yuanMdContent) {
        let content = options.yuanMdContent;
        if (content.length > 6000) {
