function formatRankingHint(ranked) {
    if (ranked.length === 0)
        return "";
    return "Suggested file reading order:\n" + ranked
        .map((f, i) => `${i + 1}. ${f.path} (score: ${f.score}, ${f.reasons.join(", ")})`)
        .join("\n");
}


