        this.totalBudget = config.totalBudget;
        this.softLimitRatio = config.softLimitRatio ?? DEFAULT_SOFT_LIMIT_RATIO;
        this.hardLimitAction = config.hardLimitAction ?? DEFAULT_HARD_LIMIT_ACTION;
        this.roles = new Map();
        for (const role of ALL_ROLES) {
