                        allowed: true,
                        role,
                        remaining,
                        reason: `Throttled: role "${role}" approaching limit. Estimated tokens halved from ${estimatedTokens} to ${throttled}.`,
                        suggestion: "Use a more concise prompt or reduce output length.",
                    };
