        for (const sid of sessionIds) {
            const sess = allSessions.get(sid);
            if (!sess || !sess.goal)
                continue;
            const t = inferTaskType(sess.goal);
            typeCounts.set(t, (typeCounts.get(t) ?? 0) + 1);
        }
        if (typeCounts.size === 0)
            return "general";
        let best = "general";
        let bestCount = 0;
        for (const [type, count] of typeCounts.entries()) {
            if (count > bestCount) {
                bestCount = count;
                best = type;
            }
        }
        return best;
    }
