/**
 * @module types
 * @description YUAN Agent Core 전체 타입 정의
 */
/** ContentBlock[] | string | null → string 변환 유틸 */
function contentToString(content) {
    if (!content)
        return "";
    if (typeof content === "string")
        return content;
    return content
        .map((b) => {
        if (b.type === "text")
            return b.text;
        if (b.type === "file")
            return `[File: ${b.name}]\n${b.content}`;
        if (b.type === "image")
            return "[Image]";
        return "";
    })
        .join("\n");
}


