class WorkspaceLock {
    locks = new Map();
    async acquire(file) {
        let release;
        const prev = this.locks.get(file);
        const next = new Promise(r => release = r);
        this.locks.set(file, next);
        if (prev)
            await prev;
        return () => {
            release();
            this.locks.delete(file);
        };
    }
}


