                cmdLower.includes("jest") ||
                cmdLower.includes("vitest") ||
                cmdLower.includes("mocha")) {
                // This IS the test run
                delta.testInvalidated = false;
                baseProbability = 0.20;
                reasoning = "test command — higher baseline failure probability (0.20)";
            }
