    let timer;
    try {
        const result = await Promise.race([
            execFileAsync(cmd, args, {
                cwd,
                maxBuffer: 1024 * 1024, // 1 MB
                timeout: timeoutMs,
            }),
            new Promise((_, reject) => {
                timer = setTimeout(() => reject(new Error("timeout")), timeoutMs);
            }),
